import{_ as t,o as n,a,ag as i}from"./chunks/framework.1whTfjCw.js";const s="/assets/index-hero.C7kgN8bw.gif",m=JSON.parse('{"title":"tnk 0.1.21","description":"","frontmatter":{},"headers":[],"relativePath":"tnk/index.md","filePath":"tnk/index.md","lastUpdated":1784506044000}'),o={name:"tnk/index.md"};function r(d,e,l,c,h,p){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="tnk-0-1-21" tabindex="-1">tnk 0.1.21 <a class="header-anchor" href="#tnk-0-1-21" aria-label="Permalink to &quot;tnk __TNK_VERSION__&quot;">​</a></h1><p>tnk is a zero-trust sandbox for local inference and secure AI coding agent runtimes. It manages the inference engine on the host, provisions per-project sandbox VMs, and provides stable service endpoints for MCP and search tooling.</p><img src="'+s+'" alt="tnk CLI demo" width="100%"><p>tnk follows Unix design principles:</p><ul><li>subcommands grouped by lifecycle domain</li><li>scriptable output (<code>text</code>, <code>json</code>, <code>ndjson</code>)</li><li>explicit defaults you must override intentionally</li><li>safe behavior when context is missing</li></ul><h2 id="why-this-exists" tabindex="-1">Why this exists <a class="header-anchor" href="#why-this-exists" aria-label="Permalink to &quot;Why this exists&quot;">​</a></h2><p>Agent stacks execute package installers, shell commands, generated scripts, and network clients with broad filesystem access. A compromised dependency gives an attacker access to your credentials, keys, and system files.</p><p>tnk reduces that risk through enforced boundaries:</p><ul><li>run agent execution inside sandbox VMs</li><li>keep host-only assets outside sandbox mounts</li><li>gate runtime context with explicit env contracts</li><li>log every sandbox session for audit and incident review</li></ul><h2 id="core-model" tabindex="-1">Core model <a class="header-anchor" href="#core-model" aria-label="Permalink to &quot;Core model&quot;">​</a></h2><ol><li><strong>Host inference runtime</strong> — managed by <code>tnk engine</code></li><li><strong>Persistent services plane</strong> — MCP bridge and search, managed by <code>tnk services</code></li><li><strong>Per-project sandbox</strong> — one sandbox per project directory, managed by <code>tnk sandbox</code></li></ol><p>The default path is <code>tnk run</code> — it boots engine + services, then you enter project sandboxes as needed.</p><p>Beyond the defaults, tnk supports the <code>mlxcel</code> inference runtime for native MLX models. See <a href="/tnk/experimental">Experimental</a> for details.</p><h2 id="read-next" tabindex="-1">Read next <a class="header-anchor" href="#read-next" aria-label="Permalink to &quot;Read next&quot;">​</a></h2><ol><li><a href="/tnk/quickstart">Quickstart</a></li><li><a href="/tnk/commands">Commands</a></li><li><a href="/tnk/sandbox">Sandbox</a></li><li><a href="/tnk/security">Security</a></li><li><a href="/tnk/configuration">Configuration</a></li></ol><hr><p><strong>See also:</strong> <a href="/tnk/quickstart">Quickstart</a> · <a href="/tnk/concepts">Concepts</a> · <a href="/tnk/security">Security</a></p>',17)])])}const k=t(o,[["render",r]]);export{m as __pageData,k as default};
